import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';

const Dashboard = () => {
  const [dadosGrafico, setDadosGrafico] = useState([]);
  const [total, setTotal] = useState(0);

  useEffect(() => {
    async function carregarDados() {
      const { data } = await supabase.from('compras').select('valor_total, categoria');
      if (data) {
        const resumo = data.reduce((acc, item) => {
          const cat = item.categoria || 'Outros';
          acc[cat] = (acc[cat] || 0) + parseFloat(item.valor_total);
          return acc;
        }, {});

        const formatado = Object.keys(resumo).map(cat => ({ name: cat, value: resumo[cat] }));
        setDadosGrafico(formatado);
        setTotal(data.reduce((sum, item) => sum + parseFloat(item.valor_total), 0));
      }
    }
    carregarDados();
  }, []);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '25px' }}>Análise de Gastos</h2>
      
      <div className="card" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div>
          <span style={{ color: 'var(--text-muted)', fontSize: '0.9rem', fontWeight: '600' }}>TOTAL GERAL</span>
          <h1 style={{ color: 'var(--primary)', margin: '5px 0 0 0' }}>
            R$ {total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h1>
        </div>
        <div style={{ textAlign: 'right' }}>
          <span className="success-tag" style={{ background: '#ecfdf5', color: '#059669', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 'bold' }}>
            Balanço Ativo
          </span>
        </div>
      </div>

      <div className="card" style={{ height: '400px', marginTop: '20px' }}>
        <h3 style={{ marginBottom: '20px', color: 'var(--text-main)' }}>Gastos por Categoria</h3>
        <ResponsiveContainer width="100%" height="80%">
          <PieChart>
            <Pie
              data={dadosGrafico}
              cx="50%"
              cy="50%"
              innerRadius={60}
              outerRadius={100}
              paddingAngle={5}
              dataKey="value"
            >
              {dadosGrafico.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
              ))}
            </Pie>
            <Tooltip 
              contentStyle={{ borderRadius: '10px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
            />
            <Legend verticalAlign="bottom" height={36}/>
          </PieChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default Dashboard;
